83	];
84	
85	// 噪音过滤：< 10KB 且无实质内容的跳过
86	const NOISE_PATTERNS = ['你好', '111', '222', 'test', '测试', '1', '2'];
87	
88	function isNoise(meta) {
89	    if (meta.sizeKB >= 10) return false;
90	    if (meta.title) return false;
91	    const msg = (meta.firstUserMsg || '').trim();
92	    if (msg.length > 10) return false;
93	    if (NOISE_PATTERNS.includes(msg)) return true;
94	    if (msg.length <= 3) return true;
95	    return false;
96	}
97	
98	async function extractConversation(jsonlPath) {
99	    const fileStream = fs.createReadStream(jsonlPath);
100	    const rl = readline.createInterface({ input: fileStream, crlfDelay: Infinity });
101	
102	    const messages = [];
103	    let title = '';
104	    let sessionId = '';
105	    let userMsgCount = 0;
106	
107	    for await (const line of rl) {
108	        if (!line.trim()) continue;
109	        try {
110	            const entry = JSON.parse(line);
111	            if (entry.sessionId && !sessionId) sessionId = entry.sessionId;
112	            if (entry.type === 'custom-title' && entry.customTitle) title = entry.customTitle;
113	            if (!title && entry.type === 'ai-title' && entry.aiTitle) title = entry.aiTitle;
114	
115	            if (entry.type === 'user' && entry.message?.role === 'user') {
116	                const text = entry.message.content?.find(c => c.type === 'text');
117	                if (text && text.text.length > 3) {
118	                    messages.push({ role: 'user', text: text.text.substring(0, 800) });
119	                    userMsgCount++;
120	                }
121	            }
122	            if (entry.type === 'assistant' && entry.message?.content && userMsgCount <= 1) {
123	                for (const c of entry.message.content) {
124	                    if (c.type === 'text' && c.text?.length > 30) {
125	                        messages.push({ role: 'assistant', text: c.text.substring(0, 500) });
126	                        break;
127	                    }
128	                }
129	            }
130	        } catch(e) {}
131	    }
132	
133	    return { sessionId, title, messages, userMsgCount };
134	}
135	
136	function classifyContent(allText, meta) {
137	    const text = allText.toLowerCase();
138	    const title = (meta.title || '').toLowerCase();
139	
140	    // 客户检测（至少匹配2个特征词才确认）
141	    const customers = [];
142	    for (const c of CUSTOMER_PATTERNS) {
143	        const matches = c.kw.filter(k => text.includes(k.toLowerCase()) || title.includes(k.toLowerCase()));
144	        if (matches.length >= 1) customers.push(c.name);
145	    }
146	
147	    // 主题检测（至少匹配2个词）
148	    const topics = [];
149	    for (const t of TOPIC_PATTERNS) {
150	        const matches = t.kw.filter(k => text.includes(k.toLowerCase()) || title.includes(k.toLowerCase()));
151	        if (matches.length >= 2) topics.push(t.topic);
152	    }
153	    if (topics.length === 0) topics.push('未分类');
154	    if (topics.length > 4) topics.length = 4; // 最多4个主题
155	
156	    return { topics, customers };
157	}
158	
159	function makeSafeTitle(meta) {
160	    if (meta.title && meta.title.length > 3 && meta.title.length < 60) {
161	        return meta.title.replace(/[\/\\:*?"<>|]/g, '-').substring(0, 50);
162	    }
163	    if (meta.firstUserMsg && meta.firstUserMsg.length > 5) {
164	        return meta.firstUserMsg.replace(/[\/\\:*?"<>|\n\r]/g, ' ').substring(0, 50).trim();
165	    }
166	    return '(无标题)';
167	}
168	
169	async function main() {
170	    const meta = JSON.parse(fs.readFileSync(META_PATH, 'utf8'));
171	
172	    // Create OB directories
173	    const months = [...new Set(meta.map(m => m.date.substring(0, 7)))].sort();
174	    for (const m of months) {
175	        fs.mkdirSync(path.join(OB_DIR, m), { recursive: true });
176	    }
177	    fs.mkdirSync(path.join(OB_DIR, '客户档案'), { recursive: true });
178	    fs.mkdirSync(path.join(OB_DIR, '主题索引'), { recursive: true });
179	
180	    const indexEntries = [];
181	    const customerMap = {};
182	    const topicMap = {};
183	    let processed = 0;
184	    let skipped = 0;
185	
186	    for (const m of meta) {
187	        if (isNoise(m)) { skipped++; continue; }
188	
189	        const filePath = path.join(PROJECTS_DIR, m.file);
190	        if (!fs.existsSync(filePath)) continue;
191	
192	        const conv = await extractConversation(filePath);
193	        const allText = conv.messages.map(msg => msg.text).join('\n');
194	        const { topics, customers } = classifyContent(allText, m);
195	
196	        const safeTitle = makeSafeTitle(m);
197	        const monthDir = m.date.substring(0, 7);
198	        const obFilename = `${m.date}_${safeTitle}.md`.replace(/\s+/g, '_').substring(0, 80);
199	        const obPath = path.join(OB_DIR, monthDir, obFilename);
200	
201	        // Skip if already exists (preserve manually created files)
202	        if (fs.existsSync(obPath)) {
203	            // Update only the metadata in index, don't overwrite
204	            indexEntries.push({ date: m.date, title: safeTitle, file: `${monthDir}/${obFilename}`, topics, customers, sessionId: m.sessionId });
205	            for (const c of customers) {
206	                if (!customerMap[c]) customerMap[c] = [];
207	                customerMap[c].push({ date: m.date, title: safeTitle, file: `${monthDir}/${obFilename}` });
208	            }
209	            for (const t of topics) {
210	                if (!topicMap[t]) topicMap[t] = [];
211	                topicMap[t].push({ date: m.date, title: safeTitle, file: `${monthDir}/${obFilename}` });
212	            }
213	            processed++;
214	            continue;
215	        }
216	
217	        // Build conversation summary
218	        let content = `---
219	date: ${m.date}
220	session_id: ${m.sessionId}
221	customers: [${customers.join(', ')}]
222	topics: [${topics.join(', ')}]
223	---
224	
225	# ${safeTitle}
226	
227	**日期**: ${m.date}
228	**消息数**: ${conv.userMsgCount}
229	
230	`;
231	
232	        // Key user messages
233	        const userMsgs = conv.messages.filter(msg => msg.role === 'user');
234	        const aiMsgs = conv.messages.filter(msg => msg.role === 'assistant');
235	
236	        if (userMsgs.length > 0) {
237	            content += `## 对话摘要\n\n`;
238	            for (const msg of userMsgs.slice(0, 3)) {
239	                content += `> ${msg.text.substring(0, 250).replace(/\n/g, ' ')}\n\n`;
240	            }
241	            if (userMsgs.length > 3) content += `*... 共 ${userMsgs.length} 条用户消息*\n\n`;
242	        }
243	
244	        if (aiMsgs.length > 0) {
245	            content += `## AI 回复要点\n\n`;
246	            for (const msg of aiMsgs.slice(0, 2)) {
247	                const shortText = msg.text.substring(0, 200).replace(/\n/g, ' ');
248	                content += `- ${shortText}\n`;
249	            }
250	        }
251	
252	        content += `\n---\n*${m.file}* | *${m.sizeKB}KB*\n`;
253	
254	        // Links
255	        if (customers.length > 0) {
256	            content += `\n## 涉及客户\n`;
257	            for (const c of customers) content += `- [[客户档案/${c}]]\n`;
258	        }
259	        if (topics.length > 0 && topics[0] !== '未分类') {
260	            content += `\n## 相关主题\n`;
261	            for (const t of topics) content += `- [[主题索引/${t}]]\n`;
262	        }
263	
264	        fs.writeFileSync(obPath, content, 'utf8');
265	
266	        indexEntries.push({ date: m.date, title: safeTitle, file: `${monthDir}/${obFilename}`, topics, customers, sessionId: m.sessionId });
267	        for (const c of customers) {
268	            if (!customerMap[c]) customerMap[c] = [];
269	            customerMap[c].push({ date: m.date, title: safeTitle, file: `${monthDir}/${obFilename}` });
270	        }
271	        for (const t of topics) {
272	            if (!topicMap[t]) topicMap[t] = [];
273	            topicMap[t].push({ date: m.date, title: safeTitle, file: `${monthDir}/${obFilename}` });
274	        }
275	
276	        processed++;
277	        if (processed % 50 === 0) console.log(`  ${processed} conversations...`);
278	    }
279	
280	    // === Write master index ===
281	    let indexContent = `# 对话归档索引\n\n> 自动生成于 ${new Date().toISOString().substring(0, 10)}\n> 共 ${processed} 个对话 | 跳过 ${skipped} 个噪音\n> [[客户档案/]] | [[主题索引/]]\n\n## 按日期\n\n`;
282	    let currentDate = '';
283	    for (const e of indexEntries) {
284	        if (e.date !== currentDate) {
285	            currentDate = e.date;
286	            indexContent += `\n### ${e.date}\n\n`;
287	        }
288	        const baseName = e.file.replace('.md', '');
289	        indexContent += `- [[${baseName}|${e.title}]]`;
290	        if (e.customers.length > 0) indexContent += `  👤 ${e.customers.join(', ')}`;
291	        if (e.topics.length > 0 && e.topics[0] !== '未分类') indexContent += `  📂 ${e.topics.slice(0,2).join(', ')}`;
292	        indexContent += '\n';
293	    }
294	
295	    indexContent += `\n## 按主题\n\n`;
296	    const sortedTopics = Object.entries(topicMap).sort((a,b) => b[1].length - a[1].length);
297	    for (const [topic, entries] of sortedTopics) {
298	        if (topic === '未分类') continue;
299	        indexContent += `### [[主题索引/${topic}]] (${entries.length})\n\n`;
300	        for (const e of entries.slice(0, 8)) {
301	            indexContent += `- [[${e.file.replace('.md', '')}|${e.date} ${e.title}]]\n`;
302	        }
303	        if (entries.length > 8) indexContent += `- ... 等 ${entries.length} 个\n`;
304	        indexContent += '\n';
305	    }
306	
307	    indexContent += `\n## 按客户\n\n`;
308	    const sortedCustomers = Object.entries(customerMap).sort((a,b) => b[1].length - a[1].length);
309	    for (const [customer, entries] of sortedCustomers) {
310	        indexContent += `### [[客户档案/${customer}]] (${entries.length})\n\n`;
311	        for (const e of entries) {
312	            indexContent += `- [[${e.file.replace('.md', '')}|${e.date} ${e.title}]]\n`;
313	        }
314	        indexContent += '\n';
315	    }
316	
317	    fs.writeFileSync(path.join(OB_DIR, '对话归档索引.md'), indexContent, 'utf8');
318	
319	    // === Write customer profiles ===
320	    for (const [customer, entries] of Object.entries(customerMap)) {
321	        const existingPath = path.join(OB_DIR, '客户档案', `${customer}.md`);
322	        let custContent = '';
323	        if (fs.existsSync(existingPath)) {
324	            custContent = fs.readFileSync(existingPath, 'utf8');
325	            if (!custContent.includes('## 全部对话时间线')) {
326	                custContent += '\n## 全部对话时间线\n\n';
327	            }
328	        } else {
329	            custContent = `# ${customer.replace(/_/g, ' ')}\n\n> 自动汇总 | ${entries.length} 个相关对话\n\n`;
330	        }
331	        // Append timeline
332	        for (const e of entries) {
333	            if (!custContent.includes(e.file.replace('.md', ''))) {
334	                custContent += `- [[../${e.file.replace('.md', '')}|${e.date} ${e.title}]]\n`;
335	            }
336	        }
337	        fs.writeFileSync(existingPath, custContent, 'utf8');
338	    }
339	
340	    // === Write topic indices ===
341	    for (const [topic, entries] of Object.entries(topicMap)) {
342	        const topicPath = path.join(OB_DIR, '主题索引', `${topic}.md`);
343	        let topicContent = `# ${topic}\n\n> ${entries.length} 个相关对话\n\n`;
344	        let lastDate = '';
345	        for (const e of entries) {
346	            if (e.date !== lastDate) {
347	                topicContent += `\n### ${e.date}\n\n`;
348	                lastDate = e.date;
349	            }
350	            topicContent += `- [[../${e.file.replace('.md', '')}|${e.title}]]\n`;
351	        }
352	        fs.writeFileSync(topicPath, topicContent, 'utf8');
353	    }
354	
355	    console.log(`\n=== V2 完成 ===`);
356	    console.log(`对话数: ${processed} | 跳过噪音: ${skipped}`);
357	    console.log(`客户档案: ${Object.keys(customerMap).length}`);
358	    console.log(`主题索引: ${Object.keys(topicMap).length}`);
359	    console.log(`索引更新: 对话归档索引.md`);
360	}
361	
362	main().catch(console.error);
